  1	package federation
  2	
  3	import (
  4		"encoding/json"
  5		"errors"
  6		"fmt"
  7		"os"
  8		"path/filepath"
  9		"sync"
 10	)
 11	
 12	// stateFileName is the on-disk filename, under XDG_DATA_HOME / ~/.local/share.
 13	const stateFileName = "federation-state.json"
 14	
 15	// fileMode is mode 0600: registry may carry spoke URLs and identity, so it is
 16	// owner-readable only (FEAT-026 NFR).
 17	const fileMode os.FileMode = 0o600
 18	
 19	// dirMode for the parent directory.
 20	const dirMode os.FileMode = 0o700
 21	
 22	// writeMu serializes concurrent SaveStateTo calls within one process so
 23	// tmpfile+rename does not race against itself. (Cross-process safety relies
 24	// on rename atomicity.)
 25	var writeMu sync.Mutex
 26	
 27	// DefaultStatePath returns ~/.local/share/ddx/federation-state.json.
 28	// Honors XDG_DATA_HOME when set, otherwise falls back to ~/.local/share.
 29	func DefaultStatePath() (string, error) {
 30		if xdg := os.Getenv("XDG_DATA_HOME"); xdg != "" {
 31			return filepath.Join(xdg, "ddx", stateFileName), nil
 32		}
 33		home, err := os.UserHomeDir()
 34		if err != nil {
 35			return "", fmt.Errorf("federation: cannot determine home directory: %w", err)
 36		}
 37		return filepath.Join(home, ".local", "share", "ddx", stateFileName), nil
 38	}
 39	
 40	// LoadStateFrom reads the registry from path. Behavior:
 41	//
 42	//   - Missing file       → fresh empty registry stamped with CurrentSchemaVersion.
 43	//   - Malformed JSON     → fresh empty registry; the corrupt file is renamed
 44	//     to "<path>.corrupt-<ts>" so an operator can recover it.
 45	//   - Unknown future     → loaded as-is; caller can inspect SchemaVersion and
 46	//     schema_version       decide whether to refuse to write.
 47	func LoadStateFrom(path string) (*FederationRegistry, error) {
 48		data, err := os.ReadFile(path)
 49		if errors.Is(err, os.ErrNotExist) {
 50			return NewRegistry(), nil
 51		}
 52		if err != nil {
 53			return nil, fmt.Errorf("federation: read state: %w", err)
 54		}
 55	
 56		var reg FederationRegistry
 57		if err := json.Unmarshal(data, &reg); err != nil {
 58			// Quarantine the corrupt file so it's not silently overwritten on the
 59			// next save, then return a fresh registry. This is the recovery path
 60			// the bead's "malformed-file recovery" AC asks for.
 61			_ = quarantineCorrupt(path)
 62			return NewRegistry(), nil
 63		}
 64	
 65		if reg.SchemaVersion == "" {
 66			// Pre-versioned files are treated as v1; future migrations would key
 67			// off the read SchemaVersion before this defaulting.
 68			reg.SchemaVersion = CurrentSchemaVersion
 69		}
 70		if reg.Spokes == nil {
 71			reg.Spokes = []SpokeRecord{}
 72		}
 73		return &reg, nil
 74	}
 75	
 76	// SaveStateTo writes the registry to path atomically: marshal → write tmpfile
 77	// in the same directory → fsync → rename onto the target. The rename is
 78	// atomic on POSIX filesystems, so a partially-written file is never visible.
 79	func SaveStateTo(path string, r *FederationRegistry) error {
 80		if r == nil {
 81			return fmt.Errorf("federation: nil registry")
 82		}
 83		if r.SchemaVersion == "" {
 84			r.SchemaVersion = CurrentSchemaVersion
 85		}
 86		if r.Spokes == nil {
 87			r.Spokes = []SpokeRecord{}
 88		}
 89	
 90		writeMu.Lock()
 91		defer writeMu.Unlock()
 92	
 93		if err := os.MkdirAll(filepath.Dir(path), dirMode); err != nil {
 94			return fmt.Errorf("federation: mkdir: %w", err)
 95		}
 96	
 97		data, err := json.MarshalIndent(r, "", "  ")
 98		if err != nil {
 99			return fmt.Errorf("federation: marshal: %w", err)
100		}
101	
102		tmp, err := os.CreateTemp(filepath.Dir(path), ".federation-state-*.json.tmp")
103		if err != nil {
104			return fmt.Errorf("federation: create tmpfile: %w", err)
105		}
106		tmpPath := tmp.Name()
107		cleanup := func() { _ = os.Remove(tmpPath) }
108	
109		if _, err := tmp.Write(data); err != nil {
110			_ = tmp.Close()
111			cleanup()
112			return fmt.Errorf("federation: write tmpfile: %w", err)
113		}
114		if err := tmp.Sync(); err != nil {
115			_ = tmp.Close()
116			cleanup()
117			return fmt.Errorf("federation: fsync tmpfile: %w", err)
118		}
119		if err := tmp.Close(); err != nil {
120			cleanup()
121			return fmt.Errorf("federation: close tmpfile: %w", err)
122		}
123		if err := os.Chmod(tmpPath, fileMode); err != nil {
124			cleanup()
125			return fmt.Errorf("federation: chmod tmpfile: %w", err)
126		}
127		if err := os.Rename(tmpPath, path); err != nil {
128			cleanup()
129			return fmt.Errorf("federation: rename: %w", err)
130		}
131		return nil
132	}
133	
134	func quarantineCorrupt(path string) error {
135		info, err := os.Stat(path)
136		if err != nil || info.IsDir() {
137			return err
138		}
139		bak := fmt.Sprintf("%s.corrupt-%d", path, info.ModTime().UnixNano())
140		return os.Rename(path, bak)
141	}

